/**
 * Edit History Tracker — PostToolUse/Write hook
 *
 * Companion to prompt/thrash-detector.ts (#1285). Maintains a rolling
 * JSONL log of recent Write/Edit events so the thrash detector can read
 * the history at UserPromptSubmit time.
 *
 * State: `.claude/state/edit-history.jsonl` — append-only, capped at
 * MAX_ENTRIES by periodic truncation on read.
 */

import { appendFileSync, mkdirSync } from 'node:fs';
import { dirname, join } from 'node:path';
import type { HookInput, HookResult, HookContext } from '../../types.js';
import { outputSilentSuccess, getField } from '../../lib/common.js';
import { NOOP_CTX } from '../../lib/context.js';

const HOOK_NAME = 'posttool/write/edit-history-tracker';
const TRACKED_TOOLS = new Set(['Write', 'Edit', 'MultiEdit']);

export function getEditHistoryPath(projectDir: string): string {
  return join(projectDir, '.claude', 'state', 'edit-history.jsonl');
}

export function editHistoryTracker(input: HookInput, ctx: HookContext = NOOP_CTX): HookResult {
  const toolName = input.tool_name || '';
  if (!TRACKED_TOOLS.has(toolName)) return outputSilentSuccess();

  const filePath = getField<string>(input, 'tool_input.file_path') || '';
  if (!filePath) return outputSilentSuccess();

  try {
    const p = getEditHistoryPath(ctx.projectDir);
    mkdirSync(dirname(p), { recursive: true });
    const entry = JSON.stringify({ t: Date.now(), f: filePath, tool: toolName });
    appendFileSync(p, `${entry}\n`);
  } catch (err) {
    ctx.log(HOOK_NAME, `Append failed: ${(err as Error).message}`);
  }

  return outputSilentSuccess();
}
